const inp=$input.first().json||{};
const strs=[]; (function col(x){if(x==null)return;if(typeof x==='string'){strs.push(x);return;}if(typeof x==='object')for(const v of Object.values(x))col(v);})(inp);
function fs(x){if(x&&typeof x==='object'&&!Array.isArray(x)){if(x.sha256!==undefined||x.hash!==undefined||x.indicator!==undefined||x.file!==undefined)return x;for(const v of Object.values(x)){const r=fs(v);if(r)return r;}}return null;}
const a=fs(inp)||{}; let h=String(a.sha256||a.hash||a.indicator||a.file||'').trim(); const all=strs.join(' ');
if(!/^[a-fA-F0-9]{64}$/.test(h)){const m=all.match(/\b[a-fA-F0-9]{64}\b/);if(m)h=m[0];}
return [{json:{hash:h}}];

const r=$input.first().json||{}; const code=(r.statusCode!==undefined)?r.statusCode:200; const body=(r.body!==undefined)?r.body:r;
const h=($('Parse').first().json||{}).hash||'';
if(!/^[a-fA-F0-9]{64}$/.test(h))return [{json:{hash:h,error:"Hybrid Analysis exige un SHA256 (64 hex). Fournis le sha256 du fichier."}}];
if(code===404)return [{json:{hash:h,found:false,msg:"Hybrid Analysis: aucun rapport pour ce hash"}}];
if(code===401||code===403)return [{json:{hash:h,error:"Hybrid Analysis: "+code+" (cle/permission)"}}];
if(code>=400)return [{json:{hash:h,error:"Hybrid Analysis HTTP "+code}}];
let b=body; if(typeof b==='string'){try{b=JSON.parse(b);}catch(e){return [{json:{hash:h,error:"reponse non JSON"}}];}}
if(!b||(Array.isArray(b)&&!b.length))return [{json:{hash:h,found:false,msg:"Hybrid Analysis: aucun rapport"}}];
return [{json:{hash:h, verdict:b.verdict||null, threat_score:(b.threat_score!==undefined?b.threat_score:null), vx_family:b.vx_family||null, type:(Array.isArray(b.type_short)?b.type_short.join(','):(b.type||null)), whitelisted:(b.whitelisted||false), dernier_nom:b.last_file_name||null, tags:(b.tags||[]).slice(0,8)}}];
